mapper.update:
UPDATE t_material_company
SET deleted_flag = #{deletedFlag}
WHERE company_id = #{companyId}

mapper.select:
SELECT *
FROM t_material_company
WHERE company_code = #{companyCode}
AND deleted_flag = #{deletedFlag}

    AND company_id != #{excludeCompanyId}

SELECT mc.*
FROM t_material_company mc

    mc.deleted_flag = #{queryForm.deletedFlag}

        AND (INSTR(mc.company_name,#{queryForm.keywords}) OR INSTR(mc.company_code,#{queryForm.keywords})
        OR INSTR(mc.contact,#{queryForm.keywords}) OR INSTR(mc.contact_phone,#{queryForm.keywords})
        OR INSTR(mc.create_user_name,#{queryForm.keywords}))


        AND DATE_FORMAT(mc.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        AND DATE_FORMAT(mc.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        AND mc.disabled_flag = #{queryForm.disabledFlag}



    ORDER BY mc.create_time DESC

SELECT mc.*
FROM t_material_company mc
WHERE mc.company_id = #{companyId}
  AND mc.deleted_flag = #{deletedFlag}
